1	//! Layer 1 External API Gateway.
2	//!
3	//! How external AI agents connect to the Agent Nervous System.
4	//! Three protocols, one gateway:
5	//!
6	//! - **MCP server** (Model Context Protocol): JSON-RPC tool provider
7	//!   for Claude, `ChatGPT`, and other MCP-compatible agents.
8	//! - **REST API**: Simple HTTP endpoints for non-MCP agents.
9	//! - **WebSocket**: Streaming events for real-time agent feedback.
10	//!
11	//! All connections are authenticated (API key), rate-limited, and
12	//! budget-tracked before any internal gRPC call is made.
13	
14	pub mod auth;
15	pub mod client;
16	pub mod mcp;
17	pub mod metrics;
18	pub mod rest;
19	pub mod ws;
20	
21	use std::net::SocketAddr;
22	use axum::routing::{get, post};
23	use axum::Router;
24	
25	use std::sync::Arc;
26	
27	use auth::SharedKeyRegistry;
28	use client::InternalClient;
29	use mcp::McpServer;
30	use metrics::Metrics;
31	use rest::ApiRouter;
32	use ws::WebSocketServer;
33	
34	/// Shared gateway state, created once at startup.
35	#[derive(Clone)]
36	pub struct Gateway {
37	    key_registry: SharedKeyRegistry,
38	    pub metrics: Arc<Metrics>,
39	    mcp: McpServer,
40	    rest: ApiRouter,
41	    ws: WebSocketServer,
42	}
43	
44	impl Gateway {
45	    /// Initialize the gateway: load API keys, connect to the daemon.
46	    pub async fn init(grpc_port: u16) -> Result<Self, Box<dyn std::error::Error>> {
47	        let key_registry = Arc::new(auth::KeyRegistry::load(None)?);
48	        let internal = InternalClient::connect(grpc_port).await?;
49	        let metrics = Arc::new(Metrics::new());
50	        let mcp = McpServer::new(internal.clone());
51	        let rest = ApiRouter::new(internal.clone());
52	        let ws = WebSocketServer::new(internal);
53	
54	        Ok(Self {
55	            key_registry,
56	            metrics,
57	            mcp,
58	            rest,
59	            ws,
60	        })
61	    }
62	
63	    /// Build the axum router.
64	    ///
65	    /// **One flat Router** — no `nest()`, no `merge()`.
66	    /// axum 0.7 `nest()` drops `{param}` captures and `merge()` with
67	    /// `route_layer` silently discards parameterized routes.
68	    /// A single flat Router with path-aware auth is the only reliable pattern.
69	    pub fn router(&self) -> Router {
70	        let rest = self.rest.clone();
71	        let mcp = self.mcp.clone();
72	        let ws = self.ws.clone();
73	        let registry = Arc::clone(&self.key_registry);
74	        let metrics_arc = Arc::clone(&self.metrics);
75	
76	        // Path-aware auth middleware: skips public routes, enforces API key on
77	        // everything else.
78	        let auth_mw = axum::middleware::from_fn({
79	            let registry = Arc::clone(&registry);
80	            move |request: axum::extract::Request, next: axum::middleware::Next| {
81	                let registry = Arc::clone(&registry);
82	                async move {
83	                    let path = request.uri().path().to_owned();
84	
85	                    // Public routes — no API key required.
86	                    if path == "/api/v1/health"
87	                        || path == "/api/v1/metrics"
88	                        || path == "/mcp"
89	                        || path == "/ws"
90	                        || path == "/"
91	                    {
92	                        return next.run(request).await;
93	                    }
94	
95	                    let api_key = auth::extract_api_key(request.headers(), None);
96	                    let valid = api_key
97	                        .as_ref()
98	                        .and_then(|k| registry.validate(k))
99	                        .is_some();
100	                    if valid {
101	                        next.run(request).await
102	                    } else {
103	                        let body = if api_key.is_some() {
104	                            r#"{"error":"invalid API key"}"#
105	                        } else {
106	                            r#"{"error":"missing X-API-Key header"}"#
107	                        };
108	                        axum::response::Response::builder()
109	                            .status(axum::http::StatusCode::UNAUTHORIZED)
110	                            .body(axum::body::Body::from(body))
111	                            .expect("building a 401 response is infallible")
112	                    }
113	                }
114	            }
115	        });
116	
117	        // Single flat Router — every route registered directly.
118	        // No nest(), no merge() — both break {param} captures in axum 0.7.
119	        Router::new()
120	            // ── Public routes ──────────────────────────────────────
121	            .route(
122	                "/",
123	                get(|| async {
124	                    axum::response::Html(include_str!("../../../static/dashboard.html"))
125	                }),
126	            )
127	            .route(
128	                "/mcp",
129	                post(
130	                    move |body: axum::extract::Json<serde_json::Value>| async move {
131	                        let response = mcp.handle_request(body.0).await;
132	                        axum::Json(response)
133	                    },
134	                ),
135	            )
136	            .route(
137	                "/ws",
138	                get(
139	                    move |ws_upgrade: axum::extract::ws::WebSocketUpgrade| async move {
140	                        ws.handle_upgrade(ws_upgrade).await
141	                    },
142	                ),
143	            )
144	            .route(
145	                "/api/v1/health",
146	                get({
147	                    let rest = rest.clone();
148	                    move || {
149	                        let rest = rest.clone();
150	                        async move { rest.health().await }
151	                    }
152	                }),
153	            )
154	            .route(
155	                "/api/v1/metrics",
156	                get(move || {
157	                    let m = Arc::clone(&metrics_arc);
158	                    async move { m.render() }
159	                }),
160	            )
161	            // ── Session routes ─────────────────────────────────────
162	            .route(
163	                "/api/v1/sessions",
164	                post({
165	                    let rest = rest.clone();
166	                    move |axum::extract::Json(body): axum::extract::Json<serde_json::Value>| async move {
167	                        rest.create_session(body).await
168	                    }
169	                }),
170	            )
171	            .route(
172	                "/api/v1/sessions/{id}/navigate",
173	                post({
174	                    let rest = rest.clone();
175	                    move |axum::extract::Path(id): axum::extract::Path<String>,
176	                          axum::extract::Json(body): axum::extract::Json<serde_json::Value>| async move {
177	                        rest.navigate(&id, body).await
178	                    }
179	                }),
180	            )
181	            .route(
182	                "/api/v1/sessions/{id}/execute",
183	                post({
184	                    let rest = rest.clone();
185	                    move |axum::extract::Path(id): axum::extract::Path<String>,
186	                          axum::extract::Json(body): axum::extract::Json<serde_json::Value>| async move {
187	                        rest.execute_action(&id, body).await
188	                    }
189	                }),
190	            )
191	            .route(
192	                "/api/v1/sessions/{id}/screenshot",
193	                post({
194	                    let rest = rest.clone();
195	                    move |axum::extract::Path(id): axum::extract::Path<String>,
196	                          axum::extract::Json(body): axum::extract::Json<serde_json::Value>| async move {
197	                        rest.screenshot(&id, body).await
198	                    }
199	                }),
200	            )
201	            .route(
202	                "/api/v1/sessions/{id}/dom",
203	                get({
204	                    let rest = rest.clone();
205	                    move |axum::extract::Path(id): axum::extract::Path<String>| async move {
206	                        rest.get_dom(&id).await
207	                    }
208	                }),
209	            )
210	            // ── Goal routes ────────────────────────────────────────
211	            .route(
212	                "/api/v1/goals",
213	                post({
214	                    let rest = rest.clone();
215	                    move |axum::extract::Json(body): axum::extract::Json<serde_json::Value>| async move {
216	                        rest.create_goal(body).await
217	                    }
218	                }),
219	            )
220	            .route(
221	                "/api/v1/goals/{id}",
222	                get({
223	                    let rest = rest.clone();
224	                    move |axum::extract::Path(id): axum::extract::Path<String>| async move {
225	                        rest.get_goal(&id).await
226	                    }
227	                }),
228	            )
229	            // Auth middleware applies to everything, but skips public paths.
230	            .route_layer(auth_mw)
231	    }
232	
233	    /// Start the gateway HTTP server on the given address.
234	    /// Blocks until the server exits.
235	    pub async fn serve(self, addr: SocketAddr) -> Result<(), Box<dyn std::error::Error>> {
236	        let router = self.router();
237	
238	        tracing::info!("Gateway starting on {}", addr);
239	
240	        let listener = tokio::net::TcpListener::bind(addr).await?;
241	        axum::serve(listener, router).await?;
242	
243	        Ok(())
244	    }
245	}
