1	//! Agent Nervous System daemon entry point.
2	//!
3	//! Starts two servers:
4	//! - gRPC server on loopback:50051 (internal Python/TS clients)
5	//! - Gateway on loopback:50052 (external AI agents — MCP, REST, WS)
6	//!
7	//! Both run concurrently. Chromium instances are cleaned up on exit
8	//! via RAII drop guards. Ctrl+C triggers graceful shutdown.
9	
10	use std::net::{IpAddr, Ipv4Addr, SocketAddr};
11	use std::path::PathBuf;
12	
13	use ans_ipc::IpcServer;
14	use clap::Parser;
15	use tracing_subscriber::EnvFilter;
16	
17	#[derive(Parser)]
18	#[command(name = "ans-daemon", version, about = "Agent Nervous System daemon")]
19	struct Cli {
20	    /// gRPC port to bind on loopback
21	    #[arg(long, default_value = "50051")]
22	    grpc_port: u16,
23	
24	    /// Gateway port to bind on loopback
25	    #[arg(long, default_value = "50052")]
26	    gateway_port: u16,
27	
28	    /// Path to ans.toml configuration file
29	    #[arg(long, default_value = "ans.toml")]
30	    config: PathBuf,
31	
32	    /// Path to nerves/ directory (Python intelligence layer)
33	    #[arg(long, default_value = "nerves")]
34	    nerves_dir: PathBuf,
35	}
36	
37	#[tokio::main]
38	async fn main() {
39	    if let Err(e) = color_eyre::install() {
40	        eprintln!("Failed to install color-eyre panic handler: {e}");
41	        std::process::exit(1);
42	    }
43	
44	    let cli = Cli::parse();
45	
46	    tracing_subscriber::fmt()
47	        .with_env_filter(
48	            EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("ans=debug,info")),
49	        )
50	        .init();
51	
52	    tracing::info!(version = env!("CARGO_PKG_VERSION"), "ans-daemon starting");
53	
54	    if let Some(cfg) = load_config(&cli.config) {
55	        tracing::info!(?cfg, "Config loaded");
56	    } else {
57	        tracing::info!("No config file found, using defaults");
58	    }
59	
60	    // ── Start gRPC server in background ──────────────────────────────
61	    let nerves_abs = if cli.nerves_dir.is_absolute() {
62	        cli.nerves_dir.clone()
63	    } else {
64	        std::env::current_dir().unwrap_or_default().join(&cli.nerves_dir)
65	    };
66	    let server = IpcServer::new().with_nerves_dir(nerves_abs);
67	    let grpc_addr = SocketAddr::new(IpAddr::V4(Ipv4Addr::LOCALHOST), cli.grpc_port);
68	
69	    let grpc_handle = tokio::spawn(async move {
70	        if let Err(e) = server.serve(grpc_addr).await {
71	            tracing::error!(%e, "gRPC server exited with error");
72	        }
73	    });
74	
75	    // Give the gRPC server a moment to bind before starting the gateway
76	    tokio::time::sleep(std::time::Duration::from_millis(300)).await;
77	
78	    // ── Start gateway ────────────────────────────────────────────────
79	    let gw_addr = SocketAddr::new(IpAddr::V4(Ipv4Addr::LOCALHOST), cli.gateway_port);
80	
81	    let gw_handle = match ans_gateway::Gateway::init(cli.grpc_port).await {
82	        Ok(gateway) => {
83	            tracing::info!("Gateway starting on {}", gw_addr);
84	            tokio::spawn(async move {
85	                if let Err(e) = gateway.serve(gw_addr).await {
86	                    tracing::error!(%e, "Gateway exited with error");
87	                }
88	            })
89	        }
90	        Err(e) => {
91	            tracing::warn!(%e, "Gateway failed to initialize — running gRPC-only");
92	            // Still wait for gRPC server
93	            let _ = grpc_handle.await;
94	            return;
95	        }
96	    };
97	
98	    // ── Wait for shutdown ────────────────────────────────────────────
99	    tokio::select! {
100	        _ = tokio::signal::ctrl_c() => {
101	            tracing::info!("Shutdown signal received");
102	        }
103	        _ = grpc_handle => {
104	            tracing::warn!("gRPC server exited unexpectedly");
105	        }
106	        _ = gw_handle => {
107	            tracing::warn!("Gateway exited unexpectedly");
108	        }
109	    }
110	
111	    tracing::info!("ans-daemon shut down cleanly");
112	}
