//! Browser pool — pre-launched Chromium instances for fast session creation.
use std::collections::VecDeque;
use std::sync::Arc;
use tokio::sync::Mutex;
use ans_cdp::CdpBackend;
use ans_stealth::StealthConfig;

pub struct BrowserPool {
    idle: Arc<Mutex<VecDeque<CdpBackend>>>,
    max_size: usize,
    min_idle: usize,  // pre-warm threshold
}

impl BrowserPool {
    #[must_use]
    pub fn new(max_size: usize) -> Self { ... }

    /// Acquire a backend: pop from pool if available, else launch fresh.
    pub async fn acquire(&self) -> Result<CdpBackend, BrowserError> { ... }

    /// Release a backend back to pool (if under max), or close it.
    pub async fn release(&self, backend: CdpBackend) { ... }

    /// Background task: maintain pool at min_idle level.
    pub async fn warmer_task(self: Arc<Self>) { ... }
}
```

Key types:
- `BrowserPool` -- owns `Arc<Mutex<VecDeque<CdpBackend>>>` 
- Uses `ans_stealth::StealthConfig` for consistency with current `SessionManager::create()`
- `acquire()` uses `tokio::sync::Mutex` (not `std::sync::RwLock`) because the lock is held briefly across a single `pop_front()` or `push_back()`
- Pool capping: if `idle.len() >= max_size`, `release()` calls `backend.close()` instead of pushing back
- Warmer task: `tokio::spawn` with `tokio::time::interval` (every 500ms), launches new backends when `idle.len() < min_idle`

